import { useState, useEffect } from 'react';
import axios from 'axios';
import { InputSwitch } from 'primereact/inputswitch';
import { Button } from 'primereact/button';
import { confirmDialog } from 'primereact/confirmdialog';

const API_BASE = 'http://localhost:8081/api/v1';

function Settings({ user, toast, onBack, onLogout }) {
  // Состояния для настроек
  const [pushNotifications, setPushNotifications] = useState(true);
  const [emailNotifications, setEmailNotifications] = useState(false);
  const [showFulfilledWishes, setShowFulfilledWishes] = useState(true);
  const [loading, setLoading] = useState(false);

  // Загружаем настройки пользователя при монтировании
  useEffect(() => {
    loadSettings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const getAuthHeaders = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  };

  const loadSettings = async () => {
    try {
      const response = await axios.get(`${API_BASE}/users/settings`, {
        headers: getAuthHeaders()
      });
      
      // Устанавливаем полученные настройки
      const settings = response.data;
      setPushNotifications(settings.pushNotifications ?? true);
      setEmailNotifications(settings.emailNotifications ?? false);
      setShowFulfilledWishes(settings.showFulfilledWishes ?? true);
    } catch (error) {
      console.error('Ошибка загрузки настроек:', error);
    }
  };

  const updateSettings = async (field, value) => {
    try {
      setLoading(true);
      await axios.patch(`${API_BASE}/users/settings`, 
        { [field]: value },
        { headers: getAuthHeaders() }
      );
      toast.current?.show({ 
        severity: 'success', 
        summary: 'Настройки обновлены', 
        life: 2000 
      });
    } catch (error) {
      toast.current?.show({ 
        severity: 'error', 
        summary: 'Ошибка обновления', 
        life: 2000 
      });
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteAccount = () => {
    confirmDialog({
      message: 'Вы уверены, что хотите удалить аккаунт? Это действие необратимо.',
      header: 'Удаление аккаунта',
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Да, удалить',
      rejectLabel: 'Отмена',
      acceptClassName: 'p-button-danger',
      accept: async () => {
        try {
          await axios.delete(`${API_BASE}/users/me`, {
            headers: getAuthHeaders()
          });
          toast.current?.show({ 
            severity: 'success', 
            summary: 'Аккаунт удален', 
            life: 2000 
          });
          setTimeout(() => {
            onLogout();
          }, 2000);
        } catch (error) {
          toast.current?.show({ 
            severity: 'error', 
            summary: 'Ошибка удаления', 
            life: 2000 
          });
        }
      }
    });
  };

  return (
    <div style={{ padding: '20px', maxWidth: '800px' }}>
      {/* Хлебные крошки */}
      <div className="breadcrumbs" style={{ marginBottom: '20px' }}>
        <i className="pi pi-home" onClick={onBack} style={{ cursor: 'pointer' }}></i>
        <i className="pi pi-angle-right"></i>
        <span>Настройки</span>
      </div>

      {/* Личные данные */}
      <div style={{ 
        background: 'white', 
        borderRadius: '12px', 
        padding: '24px',
        marginBottom: '20px'
      }}>
        <h3 style={{ marginBottom: '20px', fontSize: '18px', fontWeight: '600' }}>
          Личные данные
        </h3>
        
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          {/* Аватар */}
          <div style={{
            width: '64px',
            height: '64px',
            borderRadius: '50%',
            background: '#18B700',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'white',
            fontSize: '24px',
            fontWeight: '600'
          }}>
            {user?.name?.charAt(0).toUpperCase() || 'U'}
          </div>

          {/* Информация */}
          <div style={{ flex: 1 }}>
            <h4 style={{ margin: '0 0 8px 0', fontSize: '16px', fontWeight: '600' }}>
              {user?.name || 'Пользователь'}
            </h4>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#64748b' }}>
              <i className="pi pi-calendar" style={{ fontSize: '14px' }}></i>
              <span style={{ fontSize: '14px' }}>
                {user?.birthDate ? new Date(user.birthDate).toLocaleDateString('ru-RU') : 'Дата не указана'}
              </span>
            </div>
            <p style={{ margin: '8px 0 0 0', fontSize: '14px', color: '#64748b' }}>
              Личная информация отсутствует...
            </p>
          </div>

          {/* Кнопка редактирования */}
          <button style={{
            background: 'transparent',
            border: 'none',
            cursor: 'pointer',
            padding: '8px'
          }}>
            <i className="pi pi-pencil" style={{ fontSize: '18px', color: '#64748b' }}></i>
          </button>
        </div>
      </div>

      {/* Настройки уведомлений */}
      <div style={{ 
        background: 'white', 
        borderRadius: '12px', 
        padding: '24px',
        marginBottom: '20px'
      }}>
        <h3 style={{ marginBottom: '20px', fontSize: '18px', fontWeight: '600' }}>
          Настройки уведомлений
        </h3>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          {/* Push-уведомления */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '14px' }}>Push-уведомления</span>
            <InputSwitch 
              checked={pushNotifications} 
              onChange={(e) => {
                setPushNotifications(e.value);
                updateSettings('pushNotifications', e.value);
              }}
              disabled={loading}
            />
          </div>

          {/* Email */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '14px' }}>Email</span>
            <InputSwitch 
              checked={emailNotifications} 
              onChange={(e) => {
                setEmailNotifications(e.value);
                updateSettings('emailNotifications', e.value);
              }}
              disabled={loading}
            />
          </div>
        </div>
      </div>

      {/* Исполненные желания */}
      <div style={{ 
        background: 'white', 
        borderRadius: '12px', 
        padding: '24px',
        marginBottom: '20px'
      }}>
        <h3 style={{ marginBottom: '20px', fontSize: '18px', fontWeight: '600' }}>
          Исполненные желания
        </h3>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: '14px' }}>
            Отображать раздел "Исполненные желания" на моей странице
          </span>
          <InputSwitch 
            checked={showFulfilledWishes} 
            onChange={(e) => {
              setShowFulfilledWishes(e.value);
              updateSettings('showFulfilledWishes', e.value);
            }}
            disabled={loading}
          />
        </div>
      </div>

      {/* Кнопки действий */}
      <div style={{ display: 'flex', gap: '12px' }}>
        <Button
          label="Выйти из аккаунта"
          icon="pi pi-sign-out"
          onClick={onLogout}
          className="p-button-outlined"
          style={{ 
            color: '#ef4444', 
            borderColor: '#ef4444',
            flex: 1
          }}
        />
        <Button
          label="Удалить аккаунт"
          icon="pi pi-trash"
          onClick={handleDeleteAccount}
          className="p-button-danger"
          style={{ flex: 1 }}
        />
      </div>
    </div>
  );
}

export default Settings;
